const trig = $('Telegram Trigger').first().json;
const chatId = trig.message.chat.id;

const allowed = /\.(html|css|js|mjs|cjs|ts|jsx|tsx|json|md|txt|xml|yml|yaml|php|py|sql)$/i;
const skip = /(node_modules\/|\.git\/|dist\/|build\/|\.next\/|coverage\/|vendor\/)/i;

const MAX_FILE_CHARS = 7000;
const MAX_TOTAL_CHARS = 90000;

let files = [];
let decodedFiles = 0;
let codeBundle = '';

const items = $input.all();

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  if (!item.binary) continue;

  for (const binaryKey of Object.keys(item.binary)) {
    const b = item.binary[binaryKey];
    if (!b) continue;

    const name = b.fileName || b.filePath || binaryKey || 'unknown';
    files.push(name);

    if (!allowed.test(name) || skip.test(name)) continue;

    let text = '';
    try {
      const buf = await this.helpers.getBinaryDataBuffer(i, binaryKey);
      text = buf.toString('utf8');
    } catch (e) {
      if (typeof b.data === 'string') {
        const raw = b.data;
        const looksBase64 = /^[A-Za-z0-9+/=\r\n]+$/.test(raw) && raw.replace(/\s+/g, '').length % 4 === 0;
        text = looksBase64 ? Buffer.from(raw, 'base64').toString('utf8') : raw;
      }
    }

    if (!text || !text.trim()) continue;

    if (/^filesystem-?v2$/i.test(text.trim())) continue;

    text = text.replace(/[^\x09\x0A\x0D\x20-\uFFFF]/g, '');
    const bad = (text.match(/\x00/g) || []).length; 
    if (bad > 25) continue;

    decodedFiles++;
    codeBundle += `\n\n--- File: ${name} ---\n${text.slice(0, MAX_FILE_CHARS)}`;

    if (codeBundle.length > MAX_TOTAL_CHARS) {
      codeBundle = codeBundle.slice(0, MAX_TOTAL_CHARS) + '\n\n[truncated]';
      break;
    }
  }
}

if (!codeBundle.trim()) {
  codeBundle = `No readable code extracted. Files seen: ${files.length}`;
}

const stack = {
  hasHTML: files.some(f => /\.html$/i.test(f)),
  hasReact: files.some(f => /package\.json$/i.test(f)),
  hasPhp: files.some(f => /\.php$/i.test(f)),
  hasNode: files.some(f => /(^|\/)(server|app|index)\.js$/i.test(f)),
  hasPython: files.some(f => /\.py$/i.test(f)),
};

return [{
  json: {
    chatId,
    files,
    decodedFiles,
    stack,
    codeBundle
  }
}];

const ai = $json;
const base = $('Analyze Files + Stack + OWASP').first().json;

let report = 'No AI report generated.';
if (ai?.candidates?.[0]?.content?.parts?.[0]?.text) {
  report = ai.candidates[0].content.parts[0].text;
}

let score = 0;
const m = report.match(/(\d{1,3})\s*\/\s*100/);
if (m) score = Math.max(0, Math.min(100, Number(m[1])));

const emoji = score >= 80 ? '✅' : score >= 50 ? '⚠️' : '🚨';

const header = `${emoji} Website Test Complete\n\nOverall Score: ${score || 'N/A'}/100\nDecoded Files: ${base.decodedFiles}\nTotal Files Seen: ${base.files.length}`;

const clean = report
  .replace(/[*_~`]/g, '') 
  .replace(/\u0000/g, '');

const message = (header + '\n\n' + clean).slice(0, 3900);

return [{ json: { chatId: base.chatId, message } }];
